const amqp = require('amqplib');

async function connectRabbitMQ() {
  const connection = await amqp.connect('amqp://localhost');
  const channel = await connection.createChannel();
  
  await channel.assertQueue('task_queue', { durable: true });
  
  console.log("Waiting for messages in %s. To exit press CTRL+C", 'task_queue');

  channel.consume('task_queue', async function(msg) {
    if (!msg.content) return;
    
    const message = JSON.parse(msg.content.toString());
    console.log(`Received message: ${JSON.stringify(message, null, 2)}`);

    // Execute actions based on message type and payload
    switch (message.type) {
      case 'database-query':
        executeDatabaseQuery(message.payload);
        break;
      case 'system-command':
        executeSystemCommand(message.payload);
        break;
      default:
        console.log(`Unknown message type: ${message.type}`);
    }

    channel.ack(msg);
  }, { noAck: false });
}

async function executeDatabaseQuery(payload) {
  // Example: Construct and log a database query
  const query = `SELECT * FROM users WHERE id = ${payload.id}`;
  console.log(`Executing database query: ${query}`);
  // Add actual database execution logic here
}

function executeSystemCommand(payload) {
  // Example: Log a system command
  const command = `echo ${payload.message}`;
  console.log(`Executing system command: ${command}`);
  // Add actual command execution logic here
}

connectRabbitMQ().catch(console.error);